/** Find the last text part index in a parts array (ES2022-safe replacement for findLastIndex). */
function findLastTextIdx(parts: MessagePart[]): number {
  for (let i = parts.length - 1; i >= 0; i--) {
    if (parts[i].type === "text") return i;
  }
  return -1;
}
